namespace RecipeSharingApp.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0
        ? Math.Round((double)RatingSum / TotalRatings, 1)
        : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeSharingApp.Models;

namespace RecipeSharingApp.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;
    private readonly Lock _lock = new();

    public RecipeService()
    {
        _recipes = GetSeedRecipes();
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;
        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
            if (recipe is not null)
            {
                recipe.TotalRatings++;
                recipe.RatingSum += stars;
            }
        }
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        lock (_lock)
        {
            _recipes.Add(new Recipe
            {
                Id = _nextId++,
                Title = submission.Title.Trim(),
                Category = submission.Category.Trim(),
                Ingredients = submission.Ingredients
                    .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                    .ToList(),
                Steps = submission.Steps
                    .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                    .ToList()
            });
        }
    }

    private static List<Recipe> GetSeedRecipes() =>
    [
        new()
        {
            Id = 1, Title = "Spaghetti Carbonara", Category = "Pasta",
            Description = "A classic Roman pasta dish with eggs, cheese, pancetta, and pepper.",
            Ingredients = ["400g spaghetti", "200g pancetta", "4 egg yolks", "100g Pecorino Romano", "Black pepper"],
            Steps = [
                "Cook spaghetti in salted boiling water until al dente.",
                "Fry pancetta until crispy.",
                "Whisk egg yolks with grated Pecorino and pepper.",
                "Toss hot pasta with pancetta, then quickly stir in egg mixture off heat.",
                "Serve immediately with extra cheese and pepper."
            ],
            TotalRatings = 12, RatingSum = 52
        },
        new()
        {
            Id = 2, Title = "Chicken Tikka Masala", Category = "Curries",
            Description = "Tender chicken pieces in a creamy spiced tomato sauce.",
            Ingredients = ["500g chicken breast", "200ml yogurt", "400g canned tomatoes", "200ml cream", "2 tbsp tikka spice mix", "1 onion", "3 cloves garlic"],
            Steps = [
                "Marinate chicken in yogurt and half the spice mix for 1 hour.",
                "Grill or pan-fry chicken until charred.",
                "Sauté onion and garlic, add remaining spices.",
                "Add tomatoes and simmer 15 minutes.",
                "Stir in cream and chicken, simmer 10 more minutes."
            ],
            TotalRatings = 8, RatingSum = 35
        },
        new()
        {
            Id = 3, Title = "Caesar Salad", Category = "Salads",
            Description = "Crisp romaine lettuce with Caesar dressing, croutons, and Parmesan.",
            Ingredients = ["1 head romaine lettuce", "Caesar dressing", "Croutons", "Parmesan cheese", "Lemon juice"],
            Steps = [
                "Wash and chop romaine lettuce.",
                "Toss with Caesar dressing.",
                "Top with croutons and shaved Parmesan.",
                "Squeeze fresh lemon juice on top."
            ],
            TotalRatings = 5, RatingSum = 20
        },
        new()
        {
            Id = 4, Title = "Chocolate Lava Cake", Category = "Desserts",
            Description = "Rich chocolate cake with a molten center.",
            Ingredients = ["200g dark chocolate", "100g butter", "3 eggs", "100g sugar", "50g flour"],
            Steps = [
                "Melt chocolate and butter together.",
                "Whisk eggs and sugar until fluffy.",
                "Fold chocolate mixture into eggs, then fold in flour.",
                "Pour into greased ramekins and bake at 220°C for 12 minutes.",
                "Invert onto plates and serve immediately."
            ],
            TotalRatings = 15, RatingSum = 70
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in crispy taco shells with fresh toppings.",
            Ingredients = ["500g ground beef", "Taco seasoning", "8 taco shells", "Lettuce", "Tomato", "Cheese", "Sour cream"],
            Steps = [
                "Brown ground beef and drain fat.",
                "Add taco seasoning and water, simmer until thickened.",
                "Warm taco shells in the oven.",
                "Fill shells with beef and top with lettuce, tomato, cheese, and sour cream."
            ],
            TotalRatings = 10, RatingSum = 42
        },
        new()
        {
            Id = 6, Title = "Penne Arrabbiata", Category = "Pasta",
            Description = "Spicy tomato pasta with garlic and red chili flakes.",
            Ingredients = ["400g penne", "400g canned tomatoes", "4 cloves garlic", "Red chili flakes", "Fresh basil", "Olive oil"],
            Steps = [
                "Cook penne until al dente.",
                "Sauté garlic and chili flakes in olive oil.",
                "Add tomatoes and simmer 15 minutes.",
                "Toss pasta with sauce and garnish with fresh basil."
            ],
            TotalRatings = 6, RatingSum = 24
        }
    ];
}

@rendermode InteractiveServer

<div class="star-rating">
    <span class="rating-label">Rate this recipe:</span>
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= SelectedRating ? "filled" : "")"
                  @onclick="() => Rate(star)"
                  title="@star star(s)">★</span>
        }
    </div>
    @if (SelectedRating > 0)
    {
        <span class="rating-thanks">You rated this @SelectedRating/5!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public EventCallback<int> OnRated { get; set; }

    private int SelectedRating;

    private async Task Rate(int stars)
    {
        SelectedRating = stars;
        await OnRated.InvokeAsync(stars);
    }
}

@page "/recipes/{Category}"
@using RecipeSharingApp.Services

<PageTitle>@Category Recipes</PageTitle>

<h1>@Category Recipes</h1>

@if (_recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mb-2">
                            <span class="text-warning">@GetStarDisplay(recipe.AverageRating)</span>
                            <small class="text-muted">(@recipe.TotalRatings ratings)</small>
                        </div>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter] public string Category { get; set; } = string.Empty;

    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private List<RecipeSharingApp.Models.Recipe> _recipes = [];

    protected override void OnInitialized()
    {
        _recipes = RecipeService.GetRecipesByCategory(Category);
    }

    private static string GetStarDisplay(double rating)
    {
        int full = (int)rating;
        return new string('★', full) + new string('☆', 5 - full);
    }
}

@page "/recipe/{Id:int}"
@using RecipeSharingApp.Services
@using RecipeSharingApp.Models

<PageTitle>@(_recipe?.Title ?? "Recipe")</PageTitle>

@if (_recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
    <a href="/" class="btn btn-outline-secondary">← Back to Home</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/recipes/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <h1>@_recipe.Title</h1>
    <p class="lead">@_recipe.Description</p>

    <div class="mb-3">
        <span class="text-warning fs-5">@GetStarDisplay(_recipe.AverageRating)</span>
        <span class="text-muted">@_recipe.AverageRating / 5 (@_recipe.TotalRatings ratings)</span>
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in _recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h4>Instructions</h4>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in _recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <RecipeSharingApp.Components.StarRating
                RecipeId="@_recipe.Id"
                OnRated="HandleRating" />
        </div>
    </div>

    <a href="/recipes/@_recipe.Category" class="btn btn-outline-secondary">← Back to @_recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }

    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private Recipe? _recipe;

    protected override void OnInitialized()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }

    private void HandleRating(int stars)
    {
        RecipeService.AddRating(Id, stars);
        _recipe = RecipeService.GetRecipeById(Id);
    }

    private static string GetStarDisplay(double rating)
    {
        int full = (int)rating;
        return new string('★', full) + new string('☆', 5 - full);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeSharingApp.Models
@using RecipeSharingApp.Services

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Thank you for sharing "<strong>@_submission.Title</strong>".</p>
        <a href="/recipes/@_submission.Category" class="btn btn-primary me-2">View Category</a>
        <button class="btn btn-outline-secondary" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="_submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label" for="title">Recipe Title</label>
                    <InputText id="title" class="form-control" @bind-Value="_submission.Title"
                               placeholder="e.g., Grandma's Apple Pie" required />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="category">Category</label>
                    <InputSelect id="category" class="form-select" @bind-Value="_submission.Category" required>
                        <option value="">Select a category...</option>
                        @foreach (var cat in _categories)
                        {
                            <option value="@cat">@cat</option>
                        }
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label class="form-label" for="ingredients">Ingredients</label>
                    <InputTextArea id="ingredients" class="form-control" rows="6"
                                   @bind-Value="_submission.Ingredients"
                                   placeholder="Enter one ingredient per line" required />
                    <div class="form-text">One ingredient per line.</div>
                </div>

                <div class="mb-3">
                    <label class="form-label" for="steps">Steps</label>
                    <InputTextArea id="steps" class="form-control" rows="6"
                                   @bind-Value="_submission.Steps"
                                   placeholder="Enter one step per line" required />
                    <div class="form-text">One step per line.</div>
                </div>

                <button type="submit" class="btn btn-primary"
                        disabled="@(!IsValid)">
                    Submit Recipe
                </button>
            </div>
        </div>
    </EditForm>
}

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeSubmission _submission = new();
    private List<string> _categories = [];
    private bool _submitted;

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(_submission.Title) &&
        !string.IsNullOrWhiteSpace(_submission.Category) &&
        !string.IsNullOrWhiteSpace(_submission.Ingredients) &&
        !string.IsNullOrWhiteSpace(_submission.Steps);

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        if (!IsValid) return;
        RecipeService.AddRecipe(_submission);
        _submitted = true;
    }

    private void Reset()
    {
        _submission = new RecipeSubmission();
        _submitted = false;
    }
}

