    protected override void OnInitialized()
    {
        _recipes = RecipeService.GetRecipesByCategory(Category);
    }

    private static string GetStarDisplay(double rating)
    {
        int full = (int)rating;
        return new string('★', full) + new string('☆', 5 - full);
    }
}

