@page "/"
@using RecipeSharingApp.Services

<PageTitle>Recipe Sharing Community</PageTitle>

<div class="text-center mb-5">
    <h1>🍳 Recipe Sharing Community</h1>
    <p class="lead">Discover, share, and rate delicious recipes from around the world.</p>
</div>

<h2 class="mb-3">Browse by Category</h2>
<div class="row">
    @foreach (var category in _categories)
    {
        <div class="col-md-4 col-sm-6 mb-4">
            <a href="/recipes/@category" class="text-decoration-none">
                <div class="card h-100 category-card">
                    <div class="card-body text-center">
                        <div class="fs-1 mb-2">@GetCategoryEmoji(category)</div>
                        <h4 class="card-title">@category</h4>
                        <p class="text-muted">@GetRecipeCount(category) recipe(s)</p>
                    </div>
                </div>
            </a>
        </div>
    }
</div>

<div class="text-center mt-4">
    <a href="/submit" class="btn btn-success btn-lg">📝 Submit Your Recipe</a>
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private List<string> _categories = [];

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private int GetRecipeCount(string category) =>
        RecipeService.GetRecipesByCategory(category).Count;

    private static string GetCategoryEmoji(string category) => category switch
    {
        "Pasta" => "🍝",
        "Curries" => "🍛",
        "Salads" => "🥗",
        "Desserts" => "🍰",
        "Mexican" => "🌮",
        _ => "🍽️"
    };
}

